    for (i in 1..n) {
        for (w in 0..capacity) {
            if (weights[i - 1] > w) {
                dp[i][w] = dp[i - 1][w]
            } else {
                dp[i][w] = maxOf(dp[i - 1][w], dp[i - 1][w - weights[i - 1]] + values[i - 1])
            }
        }
    }

    return dp[n][capacity]
